import org.apache.kafka.clients.producer.KafkaProducer;
import org.apache.kafka.clients.producer.ProducerRecord;
import org.apache.kafka.common.header.Header;
import org.apache.kafka.common.header.Headers;
import java.util.Properties;

public class KafkaProducerWithCustomHeaders {
    public static void main(String[] args) {
        Properties props = new Properties();
        props.put("bootstrap.servers", "localhost:9092");
        props.put("key.serializer", "org.apache.kafka.common.serialization.StringSerializer");
        props.put("value.serializer", "org.apache.kafka.common.serialization.StringSerializer");

        KafkaProducer<String, String> producer = new KafkaProducer<>(props);

        // Read custom headers from HTTP request and create a Header object
        Map<String, Object> headers = new HashMap<>();
        headers.put("tracking-id", "1234567890");
        headers.put("user-id", "abcdefghijklmnopqrstuvwxyz");
        headers.put("custom-metadata", "custom metadata value");
        Headers kafkaHeaders = new Headers();
        for (Map.Entry<String, Object> entry : headers.entrySet()) {
            kafkaHeaders.add(new Header(entry.getKey(), entry.getValue()));
        }

        // Create a ProducerRecord with the custom headers
        String topic = "my-topic";
        ProducerRecord<String, String> producerRecord = new ProducerRecord<>(topic, null, kafkaHeaders);

        // Send the record to Kafka
        producer.send(producerRecord);

        // Close the producer
        producer.close();
    }
}